/* ======================= CHART PRIMITIVES ======================= */
function VBar({ groups, series, yMax, yStep }) {
  const W = 384, H = 196, pL = 26, pR = 6, pT = 14, pB = 26;
  const pw = W - pL - pR, ph = H - pT - pB, n = groups.length, gw = pw / n;
  const bw = (gw * 0.66) / series.length;
  const y = (v) => pT + ph - (v / yMax) * ph;
  const ticks = []; for (let v = 0; v <= yMax + 1e-6; v += yStep) ticks.push(v);
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" style={{ display: "block" }}>
      {ticks.map((t, i) => (<g key={i}><line x1={pL} y1={y(t)} x2={W - pR} y2={y(t)} stroke="#dcd8cc" strokeWidth="1" /><text x={pL - 4} y={y(t) + 3} fontSize="8" textAnchor="end" fill="#666">{t}</text></g>))}
      {groups.map((g, gi) => { const gx = pL + gi * gw; return (
        <g key={gi}>
          {series.map((s, si) => { const v = g.vals[si]; const bx = gx + gw * 0.17 + si * bw; return <rect key={si} x={bx} y={y(v)} width={bw - 2} height={pT + ph - y(v)} fill={s.color} stroke="#333" strokeWidth="0.4" />; })}
          <text x={gx + gw / 2} y={H - pB + 11} fontSize="8.5" textAnchor="middle" fill="#333">{g.label}</text>
        </g>); })}
    </svg>
  );
}
function HBar({ groups, series, xMax, xStep }) {
  const W = 384, H = 196, pL = 46, pR = 10, pT = 8, pB = 22;
  const pw = W - pL - pR, ph = H - pT - pB, n = groups.length, gh = ph / n;
  const bh = (gh * 0.6) / series.length;
  const x = (v) => pL + (v / xMax) * pw;
  const ticks = []; for (let v = 0; v <= xMax + 1e-6; v += xStep) ticks.push(v);
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" style={{ display: "block" }}>
      {ticks.map((t, i) => (<g key={i}><line x1={x(t)} y1={pT} x2={x(t)} y2={pT + ph} stroke="#dcd8cc" strokeWidth="1" /><text x={x(t)} y={H - pB + 12} fontSize="7.5" textAnchor="middle" fill="#666">{t}</text></g>))}
      {groups.map((g, gi) => { const gy = pT + gi * gh; return (
        <g key={gi}>
          {series.map((s, si) => { const v = g.vals[si]; const by = gy + gh * 0.2 + si * bh; return <rect key={si} x={pL} y={by} width={x(v) - pL} height={bh - 1.5} fill={s.color} stroke="#333" strokeWidth="0.4" />; })}
          <text x={pL - 4} y={gy + gh / 2 + 3} fontSize="8" textAnchor="end" fill="#333">{g.label}</text>
        </g>); })}
    </svg>
  );
}
function MultiLine({ series, xLabels, yMax, yStep }) {
  const W = 384, H = 196, pL = 26, pR = 12, pT = 14, pB = 24;
  const pw = W - pL - pR, ph = H - pT - pB, n = xLabels.length;
  const px = (i) => pL + (i / (n - 1)) * pw, py = (v) => pT + ph - (v / yMax) * ph;
  const ticks = []; for (let v = 0; v <= yMax + 1e-6; v += yStep) ticks.push(v);
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" style={{ display: "block" }}>
      {ticks.map((t, i) => (<g key={i}><line x1={pL} y1={py(t)} x2={W - pR} y2={py(t)} stroke="#dcd8cc" strokeWidth="1" /><text x={pL - 4} y={py(t) + 3} fontSize="8" textAnchor="end" fill="#666">{t}</text></g>))}
      {series.map((s, si) => (<g key={si}><polyline points={s.vals.map((v, i) => `${px(i)},${py(v)}`).join(" ")} fill="none" stroke={s.color} strokeWidth="2" />{s.vals.map((v, i) => <circle key={i} cx={px(i)} cy={py(v)} r="2.2" fill={s.color} />)}</g>))}
      {xLabels.map((x, i) => (<text key={i} x={px(i)} y={H - pB + 12} fontSize="8" textAnchor="middle" fill="#333">{x}</text>))}
    </svg>
  );
}
function LineChart({ pts, yMax, yStep, projFrom }) {
  const W = 384, H = 196, pL = 26, pR = 12, pT = 14, pB = 24;
  const pw = W - pL - pR, ph = H - pT - pB, n = pts.length;
  const px = (i) => pL + (i / (n - 1)) * pw, py = (v) => pT + ph - (v / yMax) * ph;
  const ticks = []; for (let v = 0; v <= yMax + 1e-6; v += yStep) ticks.push(v);
  const solid = pts.slice(0, projFrom + 1).map((p, i) => `${px(i)},${py(p.y)}`).join(" ");
  const dash = pts.slice(projFrom).map((p, i) => `${px(projFrom + i)},${py(p.y)}`).join(" ");
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" style={{ display: "block" }}>
      {ticks.map((t, i) => (<g key={i}><line x1={pL} y1={py(t)} x2={W - pR} y2={py(t)} stroke="#dcd8cc" strokeWidth="1" /><text x={pL - 4} y={py(t) + 3} fontSize="8" textAnchor="end" fill="#666">{t}</text></g>))}
      <polyline points={solid} fill="none" stroke="#1F3A5F" strokeWidth="2" />
      <polyline points={dash} fill="none" stroke="#1F3A5F" strokeWidth="2" strokeDasharray="4 3" />
      {pts.map((p, i) => (<g key={i}><circle cx={px(i)} cy={py(p.y)} r="2.4" fill="#1F3A5F" /><text x={px(i)} y={H - pB + 12} fontSize="8" textAnchor="middle" fill="#333">{p.x}</text></g>))}
      <text x={px(n - 1) - 4} y={py(pts[n - 1].y) - 6} fontSize="8" textAnchor="end" fill="#666" fontStyle="italic">projected</text>
    </svg>
  );
}
function PieChart({ slices }) {
  const cx = 92, cy = 98, r = 74, total = slices.reduce((s, x) => s + x.val, 0);
  const polar = (deg, rr) => ({ x: cx + rr * Math.cos((deg * Math.PI) / 180), y: cy + rr * Math.sin((deg * Math.PI) / 180) });
  let a = -90; const arcs = slices.map((s) => { const ang = (s.val / total) * 360; const a2 = a + ang; const large = ang > 180 ? 1 : 0; const p1 = polar(a, r); const p2 = polar(a2, r); const mid = polar((a + a2) / 2, r * 0.62); const d = `M${cx} ${cy} L${p1.x} ${p1.y} A${r} ${r} 0 ${large} 1 ${p2.x} ${p2.y} Z`; a = a2; return { d, mid, ...s }; });
  return (
    <svg viewBox="0 0 300 196" width="100%" style={{ display: "block" }}>
      {arcs.map((s, i) => (<g key={i}><path d={s.d} fill={s.color} stroke="#fff" strokeWidth="1.5" /><text x={s.mid.x} y={s.mid.y} fontSize="10" fontWeight="700" textAnchor="middle" fill="#fff">{s.val}%</text></g>))}
      {slices.map((s, i) => (<g key={i} transform={`translate(196 ${44 + i * 22})`}><rect width="12" height="12" fill={s.color} /><text x="18" y="10.5" fontSize="10.5" fill="#222">{s.label}</text></g>))}
    </svg>
  );
}
const Legend = ({ series }) => (
  <div style={{ display: "flex", flexWrap: "wrap", gap: 12, justifyContent: "center", marginTop: 6 }}>
    {series.map((s, i) => (<span key={i} style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, color: "#333" }}><span style={{ width: 11, height: 11, background: s.color, borderRadius: 2, border: "0.5px solid #333" }} />{s.name}</span>))}
  </div>
);
const pol = (cx, cy, r, deg) => ({ x: cx + r * Math.cos(deg * Math.PI / 180), y: cy + r * Math.sin(deg * Math.PI / 180) });
function TwoPie({ left, right, cats }) {
  const pie = (vals, cx) => { const tot = vals.reduce((a, b) => a + b, 0); let a = -90; return vals.map((v, i) => { const ang = v / tot * 360; const a2 = a + ang; const lg = ang > 180 ? 1 : 0; const p1 = pol(cx, 78, 40, a); const p2 = pol(cx, 78, 40, a2); const mid = pol(cx, 78, 50, (a + a2) / 2); const d = `M${cx} 78 L${p1.x} ${p1.y} A40 40 0 ${lg} 1 ${p2.x} ${p2.y} Z`; a = a2; return { d, mid, v, c: cats[i].color }; }); };
  const render = (vals, cx, label) => (<g><text x={cx} y="22" fontSize="10" fontWeight="700" textAnchor="middle" fill="#222">{label}</text>{pie(vals, cx).map((s, i) => (<g key={i}><path d={s.d} fill={s.c} stroke="#fff" strokeWidth="1" /><text x={s.mid.x} y={s.mid.y} fontSize="7.5" fontWeight="700" textAnchor="middle" fill="#333">{s.v}%</text></g>))}</g>);
  return (<svg viewBox="0 0 384 138" width="100%" style={{ display: "block" }}>{render(left, 100, "1995")}{render(right, 284, "2000")}</svg>);
}
