/* ======================= UI atoms ======================= */
const Btn = ({ children, onClick, kind = "ghost", style, disabled }) => {
  const base = { border: "none", borderRadius: 14, fontSize: 16, fontWeight: 600, padding: "14px 18px", cursor: disabled ? "default" : "pointer", opacity: disabled ? 0.4 : 1, display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 8, WebkitTapHighlightColor: "transparent" };
  const kinds = { primary: { background: C.teal, color: "#FFFFFF" }, ghost: { background: C.surface2, color: C.text }, line: { background: "transparent", color: C.text, border: `1px solid ${C.line}` } };
  return <button onClick={onClick} disabled={disabled} style={{ ...base, ...kinds[kind], ...style }}>{children}</button>;
};
const Seg = ({ options, value, onChange }) => (
  <div style={{ display: "flex", gap: 6, background: C.surface, padding: 5, borderRadius: 14 }}>
    {options.map((o) => (<button key={String(o.v)} onClick={() => onChange(o.v)} style={{ flex: 1, border: "none", borderRadius: 10, padding: "10px 4px", fontSize: 14.5, fontWeight: 600, cursor: "pointer", background: value === o.v ? C.teal : "transparent", color: value === o.v ? "#FFFFFF" : C.muted }}>{o.label}</button>))}
  </div>
);
const Ring = ({ progress, color, remaining, phaseLabel, limit, showTarget }) => {
  const R = 92, CIRC = 2 * Math.PI * R, off = CIRC * (1 - clamp(progress, 0, 1));
  const ang = ((360 * (5 / limit)) - 90) * (Math.PI / 180);
  const t1 = [110 + (R - 9) * Math.cos(ang), 110 + (R - 9) * Math.sin(ang)], t2 = [110 + (R + 9) * Math.cos(ang), 110 + (R + 9) * Math.sin(ang)];
  return (
    <div style={{ position: "relative", width: 220, height: 220, margin: "0 auto" }}>
      <svg viewBox="0 0 220 220" width="220" height="220">
        <circle cx="110" cy="110" r={R} fill="none" stroke={C.line} strokeWidth="11" />
        <circle cx="110" cy="110" r={R} fill="none" stroke={color} strokeWidth="11" strokeLinecap="round" strokeDasharray={CIRC} strokeDashoffset={off} transform="rotate(-90 110 110)" style={{ transition: "stroke-dashoffset .12s linear, stroke .35s ease" }} />
        {showTarget && limit > 5 && <line x1={t1[0]} y1={t1[1]} x2={t2[0]} y2={t2[1]} stroke={C.muted} strokeWidth="2.5" strokeLinecap="round" />}
      </svg>
      <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
        <div style={{ fontSize: 12, letterSpacing: 2, color: C.muted, textTransform: "uppercase" }}>{phaseLabel}</div>
        <div style={{ fontSize: 60, fontWeight: 700, lineHeight: 1, color: C.text, fontVariantNumeric: "tabular-nums" }}>{Math.floor(Math.max(0, remaining))}<span style={{ fontSize: 24, color: C.muted }}>.{Math.floor((Math.max(0, remaining) % 1) * 10)}</span></div>
        <div style={{ fontSize: 11, color: C.faint, marginTop: 2 }}>剩余秒</div>
      </div>
    </div>
  );
};
const Stat = ({ label, value, sub, color }) => (<div style={{ flex: 1, textAlign: "center" }}><div style={{ fontSize: 24, fontWeight: 700, color, fontVariantNumeric: "tabular-nums" }}>{value}<span style={{ fontSize: 12, color: C.faint }}> {sub}</span></div><div style={{ fontSize: 11, color: C.muted, marginTop: 3 }}>{label}</div></div>);
const Mini = ({ label, value }) => (<div><div style={{ fontSize: 11, color: C.faint }}>{label}</div><div style={{ fontSize: 15, fontWeight: 600, color: C.text, fontVariantNumeric: "tabular-nums" }}>{value}</div></div>);

/* ======================= APP ======================= */
export default function App() {
  const [screen, setScreen] = useState("setup");
  const [pick, setPick] = useState("1");
  const [singleKey, setSingleKey] = useState(0);
  const [override, setOverride] = useState("real");
  const [recordAudio, setRecordAudio] = useState(true);
  const [readAloud, setReadAloud] = useState(true);
  const [voices, setVoices] = useState([]);
  const [voiceName, setVoiceName] = useState("");
  const [history, setHistory] = useState([]);
  const [sessionName, setSessionName] = useState("");

  const [queue, setQueue] = useState([]);
  const [qPos, setQPos] = useState(0);
  const [phase, setPhase] = useState("prep");
  const [remaining, setRemaining] = useState(0);
  const [interim, setInterim] = useState("");
  const [liveSegCount, setLiveSegCount] = useState(0);
  const [results, setResults] = useState([]);
  const [sttSupported, setSttSupported] = useState(true);
  const [micError, setMicError] = useState("");

  const phaseEndRef = useRef(0), tickRef = useRef(null), recRef = useRef(null), shouldListenRef = useRef(false);
  const mediaRecRef = useRef(null), streamRef = useRef(null), chunksRef = useRef([]), audioCtxRef = useRef(null);
  const speakStartRef = useRef(0), segsRef = useRef([]), lastEndRef = useRef(0), firstSpeechRef = useRef(null), transcriptRef = useRef("");
  const firedRef = useRef({}), finishedRef = useRef(false), curSpeakRef = useRef(45), queueRef = useRef([]), posRef = useRef(0);
  const proceedRef = useRef(null), ttsUtterRef = useRef(null), micPromiseRef = useRef(null);
  const savedRef = useRef(false), fromHistoryRef = useRef(false);

  useEffect(() => { if (screen === "setup" || screen === "history") dbAll().then((l) => setHistory(l.sort((a, b) => b.when - a.when))).catch(() => {}); }, [screen]);
  useEffect(() => {
    if (screen !== "review" || !results.length || savedRef.current || fromHistoryRef.current) return;
    savedRef.current = true;
    const g = results.filter((r) => r.verdict.tone === "good").length;
    dbAdd({ when: Date.now(), name: sessionName, total: results.length, good: g, results: results.map(({ audioUrl, ...r }) => r) }).catch(() => {});
  }, [screen, results, sessionName]);

  useEffect(() => {
    if (typeof window === "undefined" || !window.speechSynthesis) return;
    const load = () => setVoices(enVoices(window.speechSynthesis.getVoices()));
    load();
    if (window.speechSynthesis.addEventListener) { window.speechSynthesis.addEventListener("voiceschanged", load); return () => window.speechSynthesis.removeEventListener("voiceschanged", load); }
  }, []);

  useEffect(() => { const SR = typeof window !== "undefined" && (window.SpeechRecognition || window.webkitSpeechRecognition); setSttSupported(!!SR); }, []);

  const beep = useCallback((freq, dur = 0.1, vol = 0.15) => {
    try { if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || window.webkitAudioContext)(); const ctx = audioCtxRef.current; const o = ctx.createOscillator(), g = ctx.createGain(); o.type = "sine"; o.frequency.value = freq; o.connect(g); g.connect(ctx.destination); const t = ctx.currentTime; g.gain.setValueAtTime(0, t); g.gain.linearRampToValueAtTime(vol, t + 0.01); g.gain.exponentialRampToValueAtTime(0.0001, t + dur); o.start(t); o.stop(t + dur + 0.02); } catch (e) {}
  }, []);

  const startSTT = useCallback(() => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition; if (!SR) return;
    const rec2 = new SR(); rec2.continuous = true; rec2.interimResults = true; rec2.lang = "en-US";
    rec2.onresult = (ev) => {
      const now = (Date.now() - speakStartRef.current) / 1000; if (firstSpeechRef.current == null) firstSpeechRef.current = now; let it = "";
      for (let i = ev.resultIndex; i < ev.results.length; i++) { const res = ev.results[i]; const txt = res[0].transcript.trim(); if (res.isFinal) { if (txt) { const start = lastEndRef.current || firstSpeechRef.current || 0; segsRef.current.push({ text: txt, start, end: now, dur: Math.max(0, now - start) }); lastEndRef.current = now; transcriptRef.current = (transcriptRef.current + " " + txt).trim(); setLiveSegCount(segsRef.current.length); } } else it += txt + " "; }
      setInterim(it.trim());
    };
    rec2.onerror = (e) => { if (e.error === "not-allowed" || e.error === "service-not-allowed") setMicError("麦克风不可用 — 计时和录音仍工作,但无法转文字。"); };
    rec2.onend = () => { if (shouldListenRef.current) { try { rec2.start(); } catch (e) {} } };
    try { rec2.start(); } catch (e) {} recRef.current = rec2;
  }, []);
  const stopSTT = useCallback(() => { shouldListenRef.current = false; if (recRef.current) { try { recRef.current.stop(); } catch (e) {} recRef.current = null; } }, []);

  const stopTTS = useCallback(() => { try { if (window.speechSynthesis) window.speechSynthesis.cancel(); } catch (e) {} }, []);
  const speakPrompt = useCallback((text, onDone) => {
    let called = false; const done = () => { if (!called) { called = true; if (onDone) onDone(); } };
    if (!readAloud || !text || typeof window === "undefined" || !window.speechSynthesis) { done(); return; }
    try {
      const synth = window.speechSynthesis;
      synth.cancel();
      // iOS/Safari: speak() right after cancel() silently fails — delay a beat; keep the
      // utterance referenced or it can be garbage-collected mid-speech and never fire onend.
      setTimeout(() => {
        try {
          const u = new SpeechSynthesisUtterance(text); u.lang = "en-US"; u.rate = 0.92; u.volume = 1;
          const v = pickVoice(synth.getVoices(), voiceName);
          if (v) u.voice = v;
          u.onend = done; u.onerror = done;
          ttsUtterRef.current = u;
          synth.resume(); synth.speak(u);
        } catch (e) { done(); }
      }, 150);
      setTimeout(done, Math.min(35000, 5000 + text.length * 100));
    } catch (e) { done(); }
  }, [readAloud, voiceName]);

  const getMic = useCallback(() => {
    if (!micPromiseRef.current) micPromiseRef.current = navigator.mediaDevices.getUserMedia({ audio: true });
    return micPromiseRef.current;
  }, []);
  const releaseMic = useCallback(() => { if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop()); streamRef.current = null; micPromiseRef.current = null; }, []);
  const startRecorder = useCallback(async () => {
    if (!recordAudio) return;
    try {
      let stream = await getMic();
      if (!stream.getTracks().some((t) => t.readyState === "live")) { micPromiseRef.current = null; stream = await getMic(); }
      streamRef.current = stream; chunksRef.current = []; const mr = new MediaRecorder(stream); mr.ondataavailable = (e) => { if (e.data.size) chunksRef.current.push(e.data); }; mr.start(); mediaRecRef.current = mr;
    } catch (e) { micPromiseRef.current = null; }
  }, [recordAudio, getMic]);
  const stopRecorder = useCallback(() => new Promise((resolve) => {
    const mr = mediaRecRef.current; if (!mr || mr.state === "inactive") { resolve(null); return; }
    mr.onstop = () => { const blob = new Blob(chunksRef.current, { type: chunksRef.current[0]?.type || "audio/webm" }); const url = URL.createObjectURL(blob); resolve({ url, mime: blob.type, blob }); };
    try { mr.stop(); } catch (e) { resolve(null); }
  }), []);

  const beginSpeak = useCallback(async (pos) => {
    stopTTS();
    const item = queueRef.current[pos]; setPhase("speak"); firedRef.current = {}; finishedRef.current = false;
    segsRef.current = []; lastEndRef.current = 0; firstSpeechRef.current = null; transcriptRef.current = ""; setLiveSegCount(0); setInterim("");
    curSpeakRef.current = item.speak; speakStartRef.current = Date.now(); phaseEndRef.current = Date.now() + item.speak * 1000; setRemaining(item.speak);
    await startRecorder();
    if (finishedRef.current) return;
    // 计时以麦克风就绪为准重置 — 权限弹窗/设备启动的时间不占用作答时间
    speakStartRef.current = Date.now(); phaseEndRef.current = Date.now() + item.speak * 1000; setRemaining(item.speak);
    beep(660, 0.08, 0.12); shouldListenRef.current = true; if (sttSupported) startSTT();
  }, [sttSupported, startSTT, startRecorder, beep, stopTTS]);

  const beginPrep = useCallback((pos) => {
    const item = queueRef.current[pos]; setInterim(""); setLiveSegCount(0); setMicError(""); firedRef.current = {}; finishedRef.current = false;
    let advanced = false;
    const proceed = () => {
      if (advanced || finishedRef.current) return; advanced = true;
      if (!item.prep) { beginSpeak(pos); return; }
      setPhase("prep"); firedRef.current = {};
      phaseEndRef.current = Date.now() + item.prep * 1000; setRemaining(item.prep);
    };
    proceedRef.current = proceed;
    if (readAloud && typeof window !== "undefined" && window.speechSynthesis) {
      setPhase("listen"); setRemaining(item.prep || 0);
      speakPrompt(item.prompt, proceed);
    } else proceed();
  }, [beginSpeak, speakPrompt, readAloud]);

  const endSpeak = useCallback(async (pos, tapped) => {
    if (finishedRef.current) return; finishedRef.current = true;
    const item = queueRef.current[pos]; const elapsed = (Date.now() - speakStartRef.current) / 1000; const finishT = tapped ? Math.min(elapsed, item.speak) : item.speak;
    stopSTT(); const audio = await stopRecorder(); const audioUrl = audio ? audio.url : null; const audioMime = audio ? audio.mime : ""; const audioBlob = audio ? audio.blob : null;
    const segs = segsRef.current.slice(); const words = transcriptRef.current ? transcriptRef.current.split(/\s+/).filter(Boolean).length : 0;
    const span = segs.length ? segs[segs.length - 1].end : finishT; const wpm = words > 3 && span > 3 ? Math.round(words / (span / 60)) : null;
    const rem = item.speak - finishT; let verdict;
    if (!tapped) verdict = { tone: "late", text: "到点被打断 — 没有主动收尾" };
    else if (rem >= 3 && rem <= 8) verdict = { tone: "good", text: `命中收尾窗口 — 提前 ${f1(rem)}s 结束` };
    else if (rem > 8) verdict = { tone: "early", text: `偏早 — 还剩 ${f1(rem)}s 没用满` };
    else verdict = { tone: "tight", text: `贴线 — 只剩 ${f1(rem)}s,收尾偏晚` };
    setResults((r) => [...r, { n: item.n, type: item.type, prompt: item.prompt, limit: item.speak, finishT, remainingAtFinish: rem, verdict, segs, transcript: transcriptRef.current, wpm, latency: firstSpeechRef.current, words, audioUrl, audioMime, audioBlob }]);
    if (pos + 1 < queueRef.current.length) { const np = pos + 1; posRef.current = np; setQPos(np); setTimeout(() => beginPrep(np), 900); }
    else { releaseMic(); clearInterval(tickRef.current); setScreen("review"); }
  }, [stopSTT, stopRecorder, beginPrep, releaseMic]);

  const runTick = useCallback(() => {
    if (finishedRef.current || phase === "listen") return;
    const rem = (phaseEndRef.current - Date.now()) / 1000; setRemaining(rem);
    if (phase === "speak") {
      const cs = curSpeakRef.current; const collect = cs <= 30 ? 8 : 10;
      if (rem <= collect && !firedRef.current.collect) { firedRef.current.collect = true; beep(523, 0.14, 0.13); }
      if (rem <= 5 && !firedRef.current.target) { firedRef.current.target = true; beep(784, 0.09, 0.14); setTimeout(() => beep(784, 0.09, 0.14), 130); }
    }
    if (rem <= 0) {
      if (phase === "prep") { if (!firedRef.current.toSpeak) { firedRef.current.toSpeak = true; beginSpeak(posRef.current); } }
      else if (!firedRef.current.buzzer) { firedRef.current.buzzer = true; beep(300, 0.28, 0.16); endSpeak(posRef.current, false); }
    }
  }, [phase, beep, beginSpeak, endSpeak]);

  useEffect(() => { if (screen !== "active") return; tickRef.current = setInterval(runTick, 80); return () => clearInterval(tickRef.current); }, [screen, runTick]);

  const start = () => {
    let q;
    if (pick === "single") { const base = POOL[singleKey]; q = [override === "real" ? base : { ...base, speak: override }]; }
    else { q = SETS.find((s) => s.key === pick).items; }
    savedRef.current = false; fromHistoryRef.current = false;
    setSessionName(pick === "single" ? "单题练习" : (SETS.find((s) => s.key === pick)?.name || ""));
    try { if (readAloud && window.speechSynthesis) { window.speechSynthesis.cancel(); window.speechSynthesis.speak(new SpeechSynthesisUtterance(" ")); } } catch (e) {}
    if (recordAudio) getMic().catch(() => { micPromiseRef.current = null; });
    queueRef.current = q; posRef.current = 0; setQueue(q); setQPos(0); setResults([]); setScreen("active"); setTimeout(() => beginPrep(0), 60);
  };
  const abort = () => { shouldListenRef.current = false; finishedRef.current = true; stopSTT(); stopTTS(); if (mediaRecRef.current && mediaRecRef.current.state !== "inactive") { try { mediaRecRef.current.stop(); } catch (e) {} } mediaRecRef.current = null; releaseMic(); clearInterval(tickRef.current); setScreen(results.length ? "review" : "setup"); };
  const reset = () => { fromHistoryRef.current = false; setScreen("setup"); setResults([]); setQPos(0); setInterim(""); setLiveSegCount(0); };
  const openHistory = (h) => {
    fromHistoryRef.current = true; setSessionName(h.name || "历史模考");
    setResults((h.results || []).map((r) => ({ ...r, audioUrl: r.audioBlob ? URL.createObjectURL(r.audioBlob) : null })));
    setScreen("review");
  };

  const item = queue[qPos];
  let ringColor = C.blue, progress = 0, phaseLabel = "准备";
  const curLimit = phase === "speak" ? (item?.speak || 45) : (item?.prep || 1);
  if (phase === "listen") { ringColor = C.blue; progress = 1; phaseLabel = "考官读题"; }
  else if (phase === "prep") { ringColor = C.blue; progress = clamp(remaining / curLimit, 0, 1); phaseLabel = "准备时间"; }
  else { progress = clamp(remaining / curLimit, 0, 1); phaseLabel = "作答中"; const collect = curLimit <= 30 ? 8 : 10; ringColor = remaining > collect ? C.green : remaining > 5 ? C.amber : C.red; }

  const wrap = { minHeight: "100%", background: C.bg, color: C.text, fontFamily: "system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif", padding: "22px 18px 40px", boxSizing: "border-box" };
  const container = { maxWidth: 460, margin: "0 auto" };
  const card = { background: C.surface, borderRadius: 18, padding: 18, border: `1px solid ${C.line}`, boxShadow: "0 1px 3px rgba(38,40,43,0.04)" };

  if (screen === "setup") {
    return (<div style={wrap}><div style={container}>
      <div style={{ marginBottom: 18 }}>
        <div style={{ fontSize: 12, letterSpacing: 3, color: C.teal, textTransform: "uppercase", fontWeight: 700 }}>UW–Madison SPEAK · 控时训练</div>
        <h1 style={{ fontSize: 26, margin: "6px 0 4px", fontWeight: 700 }}>内部时钟</h1>
        <p style={{ color: C.muted, fontSize: 14, lineHeight: 1.5, margin: 0 }}>7 套完整卷,严格按 SPEAK Form 的 9 题顺序;看图题用你自己画的图。作答页会显示这题的"急刹车"提示。环进入<span style={{ color: C.amber }}>琥珀色</span>时收束,目标在 <span style={{ color: C.text }}>5 秒</span>刻度前讲完,讲完按「我说完了」。</p>
      </div>
      <div style={{ fontSize: 13, color: C.muted, marginBottom: 8, fontWeight: 600 }}>选一套</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 14 }}>
        {SETS.map((s) => { const on = pick === s.key; return (
          <button key={s.key} onClick={() => setPick(s.key)} style={{ textAlign: "left", background: on ? C.surface2 : C.surface, border: `1.5px solid ${on ? TAGC[s.tag] : C.line}`, borderRadius: 14, padding: "12px 14px", cursor: "pointer", display: "flex", alignItems: "center", gap: 12 }}>
            <span style={{ fontSize: 11, fontWeight: 700, color: "#FFFFFF", background: TAGC[s.tag], borderRadius: 6, padding: "3px 7px", flexShrink: 0 }}>{s.tag}</span>
            <span style={{ flex: 1 }}><span style={{ display: "block", fontSize: 15, fontWeight: 600, color: C.text }}>{s.name}</span><span style={{ display: "block", fontSize: 12, color: C.faint, marginTop: 2 }}>{s.note}</span></span>
            <span style={{ fontSize: 11, color: C.muted, textAlign: "right", flexShrink: 0 }}>{s.items.length} 题<br />~{estMin(s.items)} 分</span>
          </button>); })}
        <button onClick={() => setPick("single")} style={{ textAlign: "left", background: pick === "single" ? C.surface2 : C.surface, border: `1.5px solid ${pick === "single" ? C.text : C.line}`, borderRadius: 14, padding: "12px 14px", cursor: "pointer" }}>
          <span style={{ fontSize: 15, fontWeight: 600, color: C.text }}>单题练习</span><span style={{ fontSize: 12, color: C.faint, marginLeft: 8 }}>挑一道 · 时限可调</span>
        </button>
      </div>
      {pick === "single" && (<div style={{ ...card, marginBottom: 14 }}>
        <select value={singleKey} onChange={(e) => setSingleKey(+e.target.value)} style={{ width: "100%", padding: 12, borderRadius: 12, background: C.surface2, color: C.text, border: `1px solid ${C.line}`, fontSize: 14.5 }}>
          {POOL.map((q, i) => <option key={i} value={i}>{q.n} · {q.type}</option>)}
        </select>
        <div style={{ fontSize: 13, color: C.muted, margin: "14px 0 8px", fontWeight: 600 }}>时限</div>
        <Seg options={[{ v: "real", label: "真实" }, { v: 30, label: "30s" }, { v: 45, label: "45s" }, { v: 60, label: "60s" }]} value={override} onChange={setOverride} />
      </div>)}
      <div style={{ ...card, marginBottom: 10, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div><div style={{ fontSize: 15, fontWeight: 600 }}>同时录音回放</div><div style={{ fontSize: 12, color: C.faint, marginTop: 2 }}>结束后可回听自己的作答</div></div>
        <button onClick={() => setRecordAudio((v) => !v)} style={{ width: 52, height: 30, borderRadius: 16, border: "none", cursor: "pointer", background: recordAudio ? C.teal : C.line, position: "relative" }}><span style={{ position: "absolute", top: 3, left: recordAudio ? 25 : 3, width: 24, height: 24, borderRadius: "50%", background: "#fff", transition: "left .2s" }} /></button>
      </div>
      <div style={{ ...card, marginBottom: 16 }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div><div style={{ fontSize: 15, fontWeight: 600 }}>考官朗读题目</div><div style={{ fontSize: 12, color: C.faint, marginTop: 2 }}>读题结束后才开始准备/作答,模拟现场</div></div>
          <button onClick={() => setReadAloud((v) => !v)} style={{ width: 52, height: 30, borderRadius: 16, border: "none", cursor: "pointer", background: readAloud ? C.teal : C.line, position: "relative", flexShrink: 0 }}><span style={{ position: "absolute", top: 3, left: readAloud ? 25 : 3, width: 24, height: 24, borderRadius: "50%", background: "#fff", transition: "left .2s" }} /></button>
        </div>
        {readAloud && voices.length > 0 && (<div style={{ display: "flex", gap: 8, marginTop: 12 }}>
          <select value={voiceName} onChange={(e) => setVoiceName(e.target.value)} style={{ flex: 1, minWidth: 0, padding: "10px 12px", borderRadius: 12, background: C.surface2, color: C.text, border: `1px solid ${C.line}`, fontSize: 13.5 }}>
            <option value="">自动选择声音</option>
            {voices.map((v) => <option key={v.name} value={v.name}>{v.name}{NOVELTY_VOICE.test(v.name) ? " (恶搞)" : ""} · {v.lang}</option>)}
          </select>
          <Btn kind="ghost" onClick={() => speakPrompt("Tell me about your field of study. You will have thirty seconds to answer.")} style={{ padding: "10px 14px", fontSize: 13.5, flexShrink: 0 }}>试听</Btn>
        </div>)}
      </div>
      {!sttSupported && (<div style={{ ...card, borderColor: C.amber, marginBottom: 16, display: "flex", gap: 10, alignItems: "flex-start" }}><AlertTriangle size={18} color={C.amber} style={{ flexShrink: 0, marginTop: 1 }} /><div style={{ fontSize: 13, color: C.muted, lineHeight: 1.5 }}>当前浏览器不支持实时转文字(iOS Safari / 部分 App 内置浏览器)。<b style={{ color: C.text }}>计时、变色环、提示音、录音回放照常</b>。要逐句文字复盘请用电脑版 Chrome / Edge。</div></div>)}
      <Btn kind="primary" onClick={start} style={{ width: "100%", padding: 16, fontSize: 17 }}><Mic size={18} /> 开始</Btn>
      {history.length > 0 && <Btn kind="ghost" onClick={() => setScreen("history")} style={{ width: "100%", marginTop: 10, fontSize: 15 }}><History size={16} /> 历史模考记录 ({history.length})</Btn>}
      <p style={{ fontSize: 12, color: C.faint, textAlign: "center", marginTop: 14, lineHeight: 1.6 }}>提示音:进入收尾窗口一声 → 5 秒目标点双响 → 到点低音。<br />开始后别停,像真考试一样连续录。</p>
    </div></div>);
  }

  if (screen === "history") {
    return (<div style={wrap}><div style={container}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}><h1 style={{ fontSize: 22, margin: 0, fontWeight: 700 }}>历史模考记录</h1><Btn kind="line" onClick={() => setScreen("setup")} style={{ padding: "10px 14px", fontSize: 14 }}>返回</Btn></div>
      <p style={{ fontSize: 12, color: C.faint, lineHeight: 1.6, marginTop: 0, marginBottom: 14 }}>每场模考(含录音)自动保存在本机浏览器里。注意:长期不打开本站,iPhone 可能会清理这些数据 — 重要的场次请点进去用「导出完整版」永久备份。</p>
      {history.length === 0 && <div style={{ ...card, color: C.muted, fontSize: 14 }}>还没有保存的模考,练一套就会自动出现在这里。</div>}
      {history.map((h) => (<div key={h.id} style={{ ...card, marginBottom: 12, display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 15, fontWeight: 600 }}>{h.name || "模考"}</div>
          <div style={{ fontSize: 12, color: C.faint, marginTop: 3 }}>{new Date(h.when).toLocaleString()} · {h.total} 题 · 命中收尾 {h.good}/{h.total}</div>
        </div>
        <Btn kind="ghost" onClick={() => openHistory(h)} style={{ padding: "9px 14px", fontSize: 13.5, flexShrink: 0 }}>查看</Btn>
        <button onClick={() => { dbDel(h.id).then(() => setHistory((l) => l.filter((x) => x.id !== h.id))).catch(() => {}); }} title="删除" style={{ background: "none", border: "none", color: C.faint, cursor: "pointer", padding: 6, flexShrink: 0 }}><Trash2 size={16} /></button>
      </div>))}
    </div></div>);
  }

  if (screen === "active") {
    const hint = item ? HINTS[item.type] : null;
    return (<div style={wrap}><div style={container}>
      <div style={{ position: "sticky", top: 0, zIndex: 5, background: C.bg, paddingBottom: 8, marginBottom: 8 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
          <div style={{ fontSize: 13, color: C.muted }}>{pick === "single" ? item?.n : `${qPos + 1} / ${queue.length}`} · {item?.type} · <span style={{ color: phase === "speak" ? C.text : C.blue }}>{phase === "listen" ? "考官读题中…" : phase === "prep" ? `准备 ${f1(Math.max(0, remaining))}s` : `作答 ${f1(Math.max(0, remaining))}s`}</span></div>
          <button onClick={abort} style={{ background: "none", border: "none", color: C.faint, fontSize: 13, cursor: "pointer" }}>结束</button>
        </div>
        <div style={{ height: 4, background: C.line, borderRadius: 2 }}><div style={{ width: `${progress * 100}%`, height: "100%", background: ringColor, borderRadius: 2, transition: "width .12s linear, background .35s" }} /></div>
      </div>
      <div style={{ ...card, marginBottom: 12, minHeight: 78 }}>
        <div style={{ fontSize: 11, letterSpacing: 2, color: C.teal, textTransform: "uppercase", marginBottom: 6, fontWeight: 700 }}>{item?.n}</div>
        <div style={{ fontSize: 15.5, lineHeight: 1.55 }}>{item?.prompt}</div>
      </div>
      {hint && <div style={{ fontSize: 12, color: C.amber, background: "rgba(217,119,6,0.07)", border: `1px solid ${C.line}`, borderRadius: 10, padding: "8px 12px", marginBottom: 16, lineHeight: 1.5 }}>⏱ {hint}</div>}
      {item?.visual && <Visual v={item.visual} />}
      <div style={{ marginBottom: 16 }}><Ring progress={progress} color={ringColor} remaining={remaining} phaseLabel={phaseLabel} limit={curLimit} showTarget={phase === "speak"} /></div>
      {phase === "listen" ? (
        <Btn kind="line" onClick={() => { stopTTS(); if (proceedRef.current) proceedRef.current(); }} style={{ width: "100%" }}>跳过读题 <ArrowRight size={16} /></Btn>
      ) : phase === "prep" ? (
        <Btn kind="line" onClick={() => beginSpeak(posRef.current)} style={{ width: "100%" }}>跳过准备,直接作答 <ArrowRight size={16} /></Btn>
      ) : (<>
        <Btn kind="primary" onClick={() => endSpeak(posRef.current, true)} style={{ width: "100%", padding: 16, fontSize: 17 }}><Check size={19} /> 我说完了</Btn>
        <div style={{ minHeight: 64, marginTop: 14, ...card, background: C.surface2 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: C.faint, marginBottom: 6 }}><span>实时转写{!sttSupported ? "(本设备不支持)" : ""}</span><span>{liveSegCount} 句</span></div>
          <div style={{ fontSize: 14, lineHeight: 1.5, color: C.muted }}>{sttSupported ? (transcriptRef.current ? <span style={{ color: C.text }}>{transcriptRef.current} </span> : null) : <span style={{ color: C.faint }}>正在录音…</span>}<span style={{ color: C.faint }}>{interim}</span></div>
        </div>
      </>)}
      {micError && <div style={{ marginTop: 12, fontSize: 12, color: C.amber }}>{micError}</div>}
    </div></div>);
  }

  const good = results.filter((r) => r.verdict.tone === "good").length;
  const avgRemain = results.length ? results.reduce((s, r) => s + r.remainingAtFinish, 0) / results.length : 0;
  const wpms = results.filter((r) => r.wpm).map((r) => r.wpm);
  const avgWpm = wpms.length ? Math.round(wpms.reduce((a, b) => a + b, 0) / wpms.length) : null;
  const toneColor = { good: C.green, early: C.blue, tight: C.amber, late: C.red };
  const stamp = dateStamp();
  const exportSession = () => {
    const data = {
      app: "UW–Madison SPEAK 控时训练",
      exportedAt: new Date().toISOString(),
      set: sessionName,
      summary: { total: results.length, hitWindow: good, avgRemainSec: +f1(avgRemain), avgWpm },
      results: results.map(({ audioUrl, audioMime, audioBlob, verdict, ...r }) => ({ ...r, verdict: verdict.text, hasAudio: !!audioUrl })),
    };
    shareOrDownload([{ blob: new Blob([JSON.stringify(data, null, 2)], { type: "application/json" }), name: `SPEAK_模考记录_${stamp}.json` }]);
  };
  const saveAllAudio = () => { shareOrDownload(results.filter((r) => r.audioBlob).map((r) => ({ blob: r.audioBlob, name: `SPEAK_${stamp}_${safeName(r.n)}.${extFromMime(r.audioMime)}` }))); };
  const audioCount = results.filter((r) => r.audioUrl).length;
  const exportFull = async () => {
    const lines = ["UW–Madison SPEAK 模考完整记录", `套卷: ${sessionName}`, `导出时间: ${new Date().toLocaleString()}`, `命中收尾窗口: ${good}/${results.length}` + (avgWpm ? ` · 平均语速: ${avgWpm} wpm` : ""), ""];
    results.forEach((r) => {
      lines.push(`【${r.n} · ${r.type}】时限 ${r.limit}s`, `题目: ${r.prompt}`, `判定: ${r.verdict.text}`, `用时 ${f1(r.finishT)}s` + (r.wpm ? ` · 语速 ${r.wpm} wpm` : "") + (r.words ? ` · ${r.words} 词` : ""), `转写: ${r.transcript || "(无)"}`, "");
    });
    const files = [{ blob: new Blob([lines.join("\n")], { type: "text/plain;charset=utf-8" }), name: `SPEAK_完整模考_${stamp}.txt` }];
    const withAudio = results.filter((r) => r.audioBlob);
    if (withAudio.length) {
      try {
        const ctx = new (window.AudioContext || window.webkitAudioContext)();
        const parts = [];
        for (const r of withAudio) {
          const buf = await ctx.decodeAudioData(await r.audioBlob.arrayBuffer());
          const mono = new Float32Array(buf.length);
          for (let c = 0; c < buf.numberOfChannels; c++) { const d = buf.getChannelData(c); for (let i = 0; i < d.length; i++) mono[i] += d[i] / buf.numberOfChannels; }
          parts.push(mono, new Float32Array(Math.round(ctx.sampleRate * 0.8)));
        }
        files.push({ blob: encodeWav(parts, ctx.sampleRate), name: `SPEAK_完整模考_${stamp}.wav` });
        ctx.close();
      } catch (e) { alert("拼接录音失败,先只导出文字报告,录音请用逐题保存。"); }
    }
    shareOrDownload(files);
  };
  return (<div style={wrap}><div style={container}>
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10, flexWrap: "wrap", gap: 8 }}><h1 style={{ fontSize: 22, margin: 0, fontWeight: 700 }}>训练回顾</h1><div style={{ display: "flex", gap: 8 }}><Btn kind="line" onClick={exportSession} style={{ padding: "10px 14px", fontSize: 14 }}><Download size={15} /> 导出记录</Btn><Btn kind="line" onClick={reset} style={{ padding: "10px 14px", fontSize: 14 }}><RotateCcw size={15} /> 再来一套</Btn></div></div>
    {audioCount > 0 && (<div style={{ ...card, marginBottom: 16 }}>
      <div style={{ fontSize: 12, color: C.faint, lineHeight: 1.5, marginBottom: 10 }}>本场(含录音)已自动存入首页的「历史模考记录」,随时可回听。想分享或永久备份,用下面的导出(手机上直接弹分享面板)。</div>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
        <Btn kind="primary" onClick={exportFull} style={{ padding: "10px 14px", fontSize: 13.5, flex: "1 1 auto" }}><Download size={14} /> 导出完整版(拼接录音+全文)</Btn>
        <Btn kind="ghost" onClick={saveAllAudio} style={{ padding: "10px 14px", fontSize: 13.5 }}><Download size={14} /> 逐题录音 ({audioCount})</Btn>
      </div>
    </div>)}
    {results.length > 1 && (<div style={{ ...card, marginBottom: 18 }}><div style={{ display: "flex", gap: 12 }}><Stat label="命中收尾窗口" value={`${good}/${results.length}`} color={C.green} /><Stat label="平均提前收尾" value={`${f1(avgRemain)}s`} color={avgRemain >= 3 && avgRemain <= 8 ? C.green : C.amber} /><Stat label="平均语速" value={avgWpm || "—"} sub={avgWpm ? "wpm" : ""} color={C.text} /></div></div>)}
    {results.map((r, i) => (<div key={i} style={{ ...card, marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 8 }}><div style={{ fontSize: 13, color: C.muted }}>{r.n} · {r.type}</div><div style={{ fontSize: 12, color: C.faint }}>时限 {r.limit}s</div></div>
      <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 12px", borderRadius: 12, background: C.surface2, marginBottom: 12 }}><div style={{ width: 8, height: 8, borderRadius: "50%", background: toneColor[r.verdict.tone] }} /><div style={{ fontSize: 14, fontWeight: 600, color: toneColor[r.verdict.tone] }}>{r.verdict.text}</div></div>
      <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginBottom: (r.segs.length || r.audioUrl) ? 12 : 0 }}><Mini label="收尾用时" value={`${f1(r.finishT)}s`} />{r.latency != null && <Mini label="开口延迟" value={`${f1(r.latency)}s`} />}{r.wpm && <Mini label="语速" value={`${r.wpm} wpm`} />}{r.words > 0 && <Mini label="词数" value={`${r.words}`} />}</div>
      {r.audioUrl && (<div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: r.segs.length ? 12 : 0 }}>
        <audio controls src={r.audioUrl} style={{ flex: 1, minWidth: 0, height: 36 }} />
        <button onClick={() => { const name = `SPEAK_${stamp}_${safeName(r.n)}.${extFromMime(r.audioMime)}`; if (r.audioBlob) shareOrDownload([{ blob: r.audioBlob, name }]); else dlUrl(r.audioUrl, name); }} title="保存这题录音" style={{ display: "inline-flex", alignItems: "center", gap: 5, background: C.surface2, color: C.text, border: `1px solid ${C.line}`, borderRadius: 10, padding: "8px 10px", fontSize: 12.5, fontWeight: 600, cursor: "pointer", flexShrink: 0 }}><Download size={13} /> 保存</button>
      </div>)}
      {r.segs.length > 0 && (<div><div style={{ fontSize: 12, color: C.faint, marginBottom: 8, display: "flex", justifyContent: "space-between" }}><span>分句计时</span><span>每句耗时</span></div>
        {r.segs.map((s, j) => { const w = clamp((s.dur / r.limit) * 100, 4, 100); return (<div key={j} style={{ marginBottom: 10 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 10, fontSize: 13.5, lineHeight: 1.4, marginBottom: 3 }}><span style={{ color: C.text }}>{s.text}</span><span style={{ color: C.muted, whiteSpace: "nowrap", fontVariantNumeric: "tabular-nums" }}>{f1(s.dur)}s</span></div><div style={{ height: 4, background: C.line, borderRadius: 2 }}><div style={{ width: `${w}%`, height: "100%", background: C.teal, borderRadius: 2 }} /></div><div style={{ fontSize: 10.5, color: C.faint, marginTop: 2, fontVariantNumeric: "tabular-nums" }}>{f1(s.start)}s → {f1(s.end)}s</div></div>); })}
      </div>)}
      {r.segs.length === 0 && !r.audioUrl && <div style={{ fontSize: 13, color: C.faint }}>本题无转写/录音 —— 用收尾用时对照 {r.limit - 5}s 的目标点即可。</div>}
    </div>))}
  </div></div>);
}
